/*
 * Cross-engine conformance: replay conformance/vectors.txt against the JS
 * engine. The vectors are generated by the Python reference implementation;
 * the Java and C suites replay the same file. See conformance/README.md for
 * the contract (LCG initial lattice, FNV-1a 64 hash of the final lattice).
 *
 * The LCG and hash below are independent implementations of that spec on
 * purpose -- only the engine under test is shared code.
 */
const assert = require('assert')
const fs = require('fs')
const path = require('path')
const ml = require('../src/mergelife')

const VECTORS = path.join(__dirname, '..', '..', '..', 'conformance', 'vectors.txt')

function loadVectors () {
  return fs.readFileSync(VECTORS, 'utf8')
    .split('\n')
    .map(l => l.trim())
    .filter(l => l.length > 0 && !l.startsWith('#'))
    .map(l => {
      const [rule, rows, cols, seed, steps, digest] = l.split(/\s+/)
      return {
        rule,
        rows: parseInt(rows, 10),
        cols: parseInt(cols, 10),
        seed: parseInt(seed, 10),
        steps: parseInt(steps, 10),
        digest
      }
    })
}

/* Spec PRNG: 32-bit LCG, one byte (state >>> 24) per advance. Math.imul keeps
 * the multiply exact in 32 bits. */
function lcgFill (seed, grid, rows, cols) {
  let state = seed >>> 0
  for (let row = 0; row < rows; row++) {
    for (let col = 0; col < cols; col++) {
      for (let ch = 0; ch < 3; ch++) {
        state = (Math.imul(state, 1664525) + 1013904223) >>> 0
        grid[row][col][ch] = state >>> 24
      }
    }
  }
}

/* Spec hash: FNV-1a 64-bit via BigInt, 16 lowercase hex digits. */
function fnv1a64 (bytes) {
  const MASK = 0xFFFFFFFFFFFFFFFFn
  const PRIME = 0x100000001B3n
  let h = 0xCBF29CE484222325n
  for (const b of bytes) {
    h = ((h ^ BigInt(b)) * PRIME) & MASK
  }
  return h.toString(16).padStart(16, '0')
}

function replay (v) {
  const renderer = new ml.MergeLifeRender()
  renderer.init({ rows: v.rows, cols: v.cols, rule: v.rule })
  // init() randomized grid[0]; overwrite it with the spec lattice. grid[1] is
  // already zeroed, which is all the contract requires of the back buffer.
  lcgFill(v.seed, renderer.grid[0], v.rows, v.cols)

  for (let i = 0; i < v.steps; i++) {
    renderer.singleStep()
  }

  const grid = renderer.grid[renderer.currentGrid]
  const bytes = new Uint8Array(v.rows * v.cols * 3)
  let idx = 0
  for (let row = 0; row < v.rows; row++) {
    for (let col = 0; col < v.cols; col++) {
      for (let ch = 0; ch < 3; ch++) {
        bytes[idx++] = grid[row][col][ch]
      }
    }
  }
  return fnv1a64(bytes)
}

describe('conformance', function () {
  for (const v of loadVectors()) {
    it(`matches ${v.rule.substring(0, 9)}... ${v.rows}x${v.cols} steps=${v.steps}`, function () {
      assert.strictEqual(replay(v), v.digest)
    })
  }
})
